public class Solution {
    Map<String, int[]> map = new HashMap<>();
    public int[] answerQuery(char[][] arr, int[] query) {
        preprocess(arr);
        String key = getKey(query[0], query[3], query[1], query[2]);
        return map.get(key);
    }

    public void preprocess(char[][] arr) {
        List<int[]> robotsPositions = new ArrayList<>();

        ArrayList<ArrayList<Integer>> rowWiseObstaclePosition = new ArrayList<>();
        for (int i = 0; i < arr.length; i++) {
            ArrayList<Integer> curRowPositions = new ArrayList<>();
            curRowPositions.add(-1);
            for (int j = 0; j < arr[0].length; j++) {
                if (arr[i][j] == 'X') {
                    curRowPositions.add(j);
                } else if (arr[i][j] == 'R') {
                    robotsPositions.add(new int[]{i,j});
                }
            }

            curRowPositions.add(arr[0].length);
            rowWiseObstaclePosition.add(curRowPositions);
        }

        ArrayList<ArrayList<Integer>> colWiseObstaclePosition = new ArrayList<>();
        for (int j = 0; j < arr[0].length; j++) {
            ArrayList<Integer> curColPositions = new ArrayList<>();
            curColPositions.add(-1);
            for (int i = 0; i < arr.length; i++) {
                if (arr[i][j] == 'X') {
                    curColPositions.add(i);
                }
            }
            curColPositions.add(arr.length);
            colWiseObstaclePosition.add(curColPositions);
        }

        for (int[] pos : robotsPositions) {
            int posI = pos[0];
            int posJ = pos[1];
            int leftObstaclePosition = biggestNumberThatIsSmallerThan(posJ, rowWiseObstaclePosition.get(posI));
            int rightObstaclePosition = smallestNumberThatIsGreaterThan(posJ, rowWiseObstaclePosition.get(posI));
            int topObstaclePosition = biggestNumberThatIsSmallerThan(posI, colWiseObstaclePosition.get(posJ));
            int bottomObstaclePosition = smallestNumberThatIsGreaterThan(posI, colWiseObstaclePosition.get(posJ));

            int leftDist = posJ - leftObstaclePosition;
            int rightDist = rightObstaclePosition - posJ;
            int topDist = posI - topObstaclePosition;
            int bottomDist = bottomObstaclePosition - posI;

            String key = getKey(leftDist, rightDist, topDist, bottomDist);

            map.put(key, new int[]{posI, posJ});
        }

    }

    private String getKey(int left, int right, int top, int bottom) {
        return " " + left + " : " + right + " : " + top + " : " + bottom;
    }

    public int biggestNumberThatIsSmallerThan(int cur, List<Integer> list) {
        int low = 0;
        int high = list.size()-1;

        while (low <= high) {
            int mid = low + (high - low)/2;
            if (list.get(mid) > cur) {
                high = mid-1;
            } else {
                low = mid+1;
            }
        }

        return list.get(high);
    }

    public int smallestNumberThatIsGreaterThan(int cur, List<Integer> list) {
        int low = 0;
        int high = list.size() - 1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (list.get(mid) < cur) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        return list.get(low);
    }

    public static void main(String[] args) {
        Solution sol = new Solution();
        int[] arr = new int[]{-1,2,3,4,5};
        List<Integer> list = new ArrayList<>();
        for (int num : arr) {
            list.add(num);
        }

        System.out.println(sol.biggestNumberThatIsSmallerThan(1, list));
        System.out.println(sol.smallestNumberThatIsGreaterThan(1, list));

        char[][] board = new char[][] {
                {'R', 'E', 'E', 'E', 'X'},
                {'E', 'R', 'X', 'X', 'X'},
                {'E', 'E', 'E', 'E', 'E'},
                {'X', 'E', 'R', 'E', 'X'},
                {'X', 'E', 'X', 'E', 'X'}
        };

        System.out.println(Arrays.toString(sol.answerQuery(board, new int[]{2,2,4,1})) );
    }
}

